UI_TEXT = 'function acrModuleClassColor(moduleName) {\n    return {\n        MODULE_1_CT_NUMBER: "#8b5cf6",\n        MODULE_2_LOW_CONTRAST: "#0ea5e9",\n        MODULE_3_UNIFORMITY: "#16a34a",\n        MODULE_4_HIGH_CONTRAST: "#f97316",\n        TRANSITION_OR_UNKNOWN: "#64748b"\n    }[moduleName] || "#64748b";\n}\n\nfunction findOriginalWholeStackButton() {\n    const excludedIds = new Set([\n        "acrSplitModulesButton",\n        "acrModuleClassifierToolbarButton",\n        "runAcrModuleClassifierButton",\n        "runAutomaticModule3Button"\n    ]);\n\n    return Array.from(document.querySelectorAll("button")).find((button) => {\n        if (excludedIds.has(button.id)) return false;\n\n        const text = (button.textContent || "")\n            .trim()\n            .toLowerCase();\n\n        return (\n            text.includes("scan whole")\n            || text.includes("whole ct stack")\n            || text.includes("whole stack")\n        );\n    }) || null;\n}\n\n\nfunction getDicomBottomTarget() {\n    const selectors = [\n        "#dicomRoiWorkspace",\n        "#dicom-roi-workspace",\n        ".dicom-roi-workspace",\n        "#dicomWorkspace",\n        ".dicom-workspace",\n        "#dicomSection",\n        ".dicom-section",\n        "main"\n    ];\n\n    for (const selector of selectors) {\n        const element = document.querySelector(selector);\n\n        if (element) {\n            return element;\n        }\n    }\n\n    return document.body;\n}\n\n\nfunction getDicomBottomHost(show = false) {\n    let host = document.getElementById(\n        "dicomAutomaticAnalysisBottomHost"\n    );\n\n    if (!host) {\n        host = document.createElement("section");\n        host.id = "dicomAutomaticAnalysisBottomHost";\n        host.style.cssText =\n            "display:none;width:100%;box-sizing:border-box;"\n            + "margin-top:24px;padding-top:4px;";\n\n        const target = getDicomBottomTarget();\n        target.appendChild(host);\n    } else {\n        // Re-append the host so it remains the final item at the bottom of\n        // the DICOM workspace even if the page rebuilds parts of the UI.\n        const target = getDicomBottomTarget();\n\n        if (host.parentElement !== target || target.lastElementChild !== host) {\n            target.appendChild(host);\n        }\n    }\n\n    if (show) {\n        host.style.display = "block";\n    }\n\n    return host;\n}\n\n\nfunction getOriginalModule3ResultsContainer(show = false) {\n    const host = getDicomBottomHost(show);\n\n    let container = document.getElementById(\n        "automaticModule3OriginalResults"\n    );\n\n    if (!container) {\n        container = document.createElement("div");\n        container.id = "automaticModule3OriginalResults";\n        container.style.marginTop = "14px";\n        host.appendChild(container);\n    }\n\n    if (show) {\n        host.style.display = "block";\n    }\n\n    return container;\n}\n\n\nfunction showOriginalModule3Status(message, isError = false) {\n    const container = getOriginalModule3ResultsContainer(true);\n\n    container.innerHTML = `\n        <div style="\n            padding:12px;\n            border:1px solid ${isError ? "#fecaca" : "#bae6fd"};\n            background:${isError ? "#fef2f2" : "#f0f9ff"};\n            color:${isError ? "#991b1b" : "#075985"};\n            border-radius:9px;\n        ">\n            ${message}\n        </div>\n    `;\n}\n\n\nfunction ensureAcrModuleClassifierUi(showPanel = false) {\n    let panel = document.getElementById("acrModuleClassifierPanel");\n\n    if (!panel) {\n        panel = document.createElement("section");\n        panel.id = "acrModuleClassifierPanel";\n        panel.style.cssText =\n            "display:none;margin-top:18px;border:1px solid #dbe3ee;"\n            + "border-radius:14px;background:#fff;padding:16px;";\n\n        panel.innerHTML = `\n            <div style="display:flex;align-items:center;justify-content:space-between;gap:12px;flex-wrap:wrap;">\n                <div>\n                    <div style="font-size:18px;font-weight:800;">Split Modules</div>\n                    <div style="font-size:13px;color:#64748b;margin-top:4px;">\n                        Four-module ranges, category scores, and exact Module 3 BB-slice ranking.\n                    </div>\n                </div>\n                <button\n                    id="hideAcrModuleClassifierButton"\n                    type="button"\n                    style="\n                        padding:8px 12px;\n                        border:1px solid #cbd5e1;\n                        border-radius:8px;\n                        background:#fff;\n                        color:#334155;\n                        font-weight:700;\n                        cursor:pointer;\n                    "\n                >\n                    Hide\n                </button>\n            </div>\n\n            <div\n                id="acrModuleClassifierStatus"\n                style="margin-top:12px;color:#475569;"\n            ></div>\n\n            <div\n                id="acrModuleClassifierResults"\n                style="margin-top:14px;"\n            ></div>\n        `;\n\n        const bottomHost = getDicomBottomHost(false);\n        bottomHost.appendChild(panel);\n\n        document\n            .getElementById("hideAcrModuleClassifierButton")\n            .addEventListener("click", () => {\n                panel.style.display = "none";\n            });\n    }\n\n    if (showPanel) {\n        const bottomHost = getDicomBottomHost(true);\n        panel.style.display = "block";\n\n        bottomHost.scrollIntoView({\n            behavior: "smooth",\n            block: "start"\n        });\n    }\n\n    return panel;\n}\n\n\nfunction removeOldDuplicateModuleButtons() {\n    const oldToolbar = document.getElementById(\n        "acrModuleClassifierToolbarButton"\n    );\n\n    if (oldToolbar) {\n        oldToolbar.remove();\n    }\n\n    for (const button of Array.from(document.querySelectorAll("button"))) {\n        if (button.id === "acrSplitModulesButton") continue;\n\n        const text = (button.textContent || "")\n            .trim()\n            .toLowerCase();\n\n        if (\n            text === "classify + find best m3 slice"\n            || text === "classify and find best m3 slice"\n            || text === "run automatic module 3 analysis"\n        ) {\n            button.remove();\n        }\n    }\n}\n\n\nfunction ensureSplitModulesButton() {\n    removeOldDuplicateModuleButtons();\n\n    const wholeStackButton = findOriginalWholeStackButton();\n\n    if (!wholeStackButton) {\n        return null;\n    }\n\n    let splitButton = document.getElementById(\n        "acrSplitModulesButton"\n    );\n\n    if (!splitButton) {\n        splitButton = wholeStackButton.cloneNode(true);\n        splitButton.id = "acrSplitModulesButton";\n        splitButton.type = "button";\n        splitButton.textContent = "Split Modules";\n        splitButton.removeAttribute("onclick");\n        splitButton.disabled = false;\n        splitButton.title =\n            "Show the four-module classification map and per-slice scores.";\n\n        splitButton.addEventListener("click", (event) => {\n            event.preventDefault();\n            event.stopPropagation();\n            runAcrModuleClassification();\n        });\n\n        wholeStackButton.insertAdjacentElement(\n            "afterend",\n            splitButton\n        );\n    }\n\n    return splitButton;\n}\n\n\nfunction bindOriginalWholeStackButton() {\n    const button = findOriginalWholeStackButton();\n\n    if (!button || button.dataset.integratedModule3Bound === "1") {\n        return button;\n    }\n\n    button.dataset.integratedModule3Bound = "1";\n\n    button.addEventListener(\n        "click",\n        async (event) => {\n            event.preventDefault();\n            event.stopPropagation();\n            event.stopImmediatePropagation();\n\n            await runAutomaticModule3Analysis(button);\n        },\n        true\n    );\n\n    return button;\n}\n\n\nfunction setupAcrModuleControls() {\n    removeOldDuplicateModuleButtons();\n    bindOriginalWholeStackButton();\n    ensureSplitModulesButton();\n\n    // Keep the split panel hidden until the third button is clicked.\n    const panel = ensureAcrModuleClassifierUi(false);\n    panel.style.display = "none";\n\n    const bottomHost = getDicomBottomHost(false);\n\n    if (\n        !document.getElementById("automaticModule3OriginalResults")?.innerHTML.trim()\n        && panel.style.display === "none"\n    ) {\n        bottomHost.style.display = "none";\n    }\n}\n\nfunction moduleScoreBar(value, moduleName) {\n    const safeValue = Math.max(0, Math.min(100, Number(value || 0)));\n    const color = acrModuleClassColor(moduleName);\n\n    return `\n        <div style="min-width:72px;">\n            <div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:3px;">\n                <span>${safeValue}</span><span style="color:#94a3b8;">/100</span>\n            </div>\n            <div style="height:6px;background:#e5e7eb;border-radius:999px;overflow:hidden;">\n                <div style="width:${safeValue}%;height:100%;background:${color};"></div>\n            </div>\n        </div>\n    `;\n}\n\n\nfunction module3TargetScoreBar(slice) {\n    if (slice.module3TargetScore === null || slice.module3TargetScore === undefined) {\n        return `<span style="color:#94a3b8;">—</span>`;\n    }\n\n    const score = Math.max(0, Math.min(100, Number(slice.module3TargetScore || 0)));\n    const accepted = Boolean(slice.module3TargetAccepted);\n    const color = accepted ? "#0891b2" : "#94a3b8";\n    const rank = slice.module3TargetRank ? `#${slice.module3TargetRank}` : "";\n\n    return `\n        <div style="min-width:92px;">\n            <div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:3px;">\n                <span style="font-weight:${slice.module3TargetRank === 1 ? 800 : 500};">${score.toFixed(1)}</span>\n                <span style="color:#64748b;">${rank}</span>\n            </div>\n            <div style="height:7px;background:#e5e7eb;border-radius:999px;overflow:hidden;">\n                <div style="width:${score}%;height:100%;background:${color};"></div>\n            </div>\n        </div>\n    `;\n}\n\n\nfunction moduleReasons(slice) {\n    const reasons =\n        (slice.reasons && slice.reasons[slice.prediction]) ||\n        (slice.reasons && slice.reasons.TRANSITION_OR_UNKNOWN) ||\n        [];\n\n    const categoryText = reasons.length ? reasons.join("; ") : "No strong category evidence recorded.";\n\n    if (slice.prediction === "MODULE_3_UNIFORMITY" && slice.module3TargetReason) {\n        return `${categoryText}; exact-slice ranking: ${slice.module3TargetReason}`;\n    }\n\n    return categoryText;\n}\n\nfunction renderAcrModuleClassification(data) {\n    const results = document.getElementById("acrModuleClassifierResults");\n    if (!results) return;\n\n    const labels = data.moduleLabels || {};\n    const groups = data.groups || [];\n    const slices = data.slices || [];\n    const probable = data.probableModule3Group;\n    const best = data.bestModule3Slice;\n    window.latestAcrModuleClassification = data;\n\n    const order = [\n        "MODULE_1_CT_NUMBER",\n        "MODULE_2_LOW_CONTRAST",\n        "MODULE_3_UNIFORMITY",\n        "MODULE_4_HIGH_CONTRAST",\n        "TRANSITION_OR_UNKNOWN"\n    ];\n\n    const countCards = order.map((name) => {\n        const count = (data.counts && data.counts[name]) || 0;\n        return `\n            <div style="border:1px solid #e2e8f0;border-radius:10px;padding:10px 12px;min-width:145px;flex:1;">\n                <div style="font-size:12px;color:#64748b;">${labels[name] || name}</div>\n                <div style="font-size:22px;font-weight:800;color:${acrModuleClassColor(name)};margin-top:3px;">${count}</div>\n                <div style="font-size:11px;color:#94a3b8;">slice${count === 1 ? "" : "s"}</div>\n            </div>\n        `;\n    }).join("");\n\n    const total = Math.max(1, Number(data.sliceCount || 0));\n    const map = groups.map((group) => {\n        const width = Math.max(1.2, Number(group.sliceCount || 0) / total * 100);\n        const title = `${group.predictionLabel}: slices ${group.startSliceNumber}-${group.endSliceNumber}`;\n        return `\n            <div title="${title}" style="width:${width}%;min-width:3px;height:34px;background:${acrModuleClassColor(group.prediction)};border-right:1px solid rgba(255,255,255,.8);display:flex;align-items:center;justify-content:center;color:#fff;font-size:10px;font-weight:700;overflow:hidden;white-space:nowrap;">\n                ${group.sliceCount >= 4 ? `${group.startSliceNumber}-${group.endSliceNumber}` : ""}\n            </div>\n        `;\n    }).join("");\n\n    const groupRows = groups.map((group) => `\n        <tr>\n            <td style="padding:8px;border-bottom:1px solid #e5e7eb;">${group.startSliceNumber}-${group.endSliceNumber}</td>\n            <td style="padding:8px;border-bottom:1px solid #e5e7eb;color:${acrModuleClassColor(group.prediction)};font-weight:700;">${group.predictionLabel}</td>\n            <td style="padding:8px;border-bottom:1px solid #e5e7eb;text-align:center;">${group.sliceCount}</td>\n            <td style="padding:8px;border-bottom:1px solid #e5e7eb;text-align:center;">${group.averageScores.MODULE_1_CT_NUMBER}</td>\n            <td style="padding:8px;border-bottom:1px solid #e5e7eb;text-align:center;">${group.averageScores.MODULE_2_LOW_CONTRAST}</td>\n            <td style="padding:8px;border-bottom:1px solid #e5e7eb;text-align:center;">${group.averageScores.MODULE_3_UNIFORMITY}</td>\n            <td style="padding:8px;border-bottom:1px solid #e5e7eb;text-align:center;">${group.averageScores.MODULE_4_HIGH_CONTRAST}</td>\n        </tr>\n    `).join("");\n\n    const sliceRows = slices.map((slice) => {\n        const scores = slice.scores || {};\n        const isBest = Boolean(best && Number(best.sliceNumber) === Number(slice.sliceNumber));\n        const rowBackground = isBest ? "#ecfeff" : "#ffffff";\n\n        return `\n            <tr style="background:${rowBackground};">\n                <td style="padding:8px;border-bottom:1px solid #e5e7eb;position:sticky;left:0;background:${rowBackground};z-index:1;">\n                    <span style="font-weight:${isBest ? 900 : 500};">${slice.sliceNumber}</span>\n                    ${isBest ? `<div style="font-size:10px;color:#0e7490;font-weight:800;">BEST BB SLICE</div>` : ""}\n                </td>\n                <td style="padding:8px;border-bottom:1px solid #e5e7eb;min-width:205px;">\n                    <div style="font-weight:700;color:${acrModuleClassColor(slice.prediction)};">${slice.predictionLabel}</div>\n                    <div style="font-size:11px;color:#64748b;">${slice.confidenceLabel || "Low"} category confidence · margin ${slice.scoreMargin || 0}</div>\n                </td>\n                <td style="padding:8px;border-bottom:1px solid #e5e7eb;">${moduleScoreBar(scores.MODULE_1_CT_NUMBER, "MODULE_1_CT_NUMBER")}</td>\n                <td style="padding:8px;border-bottom:1px solid #e5e7eb;">${moduleScoreBar(scores.MODULE_2_LOW_CONTRAST, "MODULE_2_LOW_CONTRAST")}</td>\n                <td style="padding:8px;border-bottom:1px solid #e5e7eb;">${moduleScoreBar(scores.MODULE_3_UNIFORMITY, "MODULE_3_UNIFORMITY")}</td>\n                <td style="padding:8px;border-bottom:1px solid #e5e7eb;">${moduleScoreBar(scores.MODULE_4_HIGH_CONTRAST, "MODULE_4_HIGH_CONTRAST")}</td>\n                <td style="padding:8px;border-bottom:1px solid #e5e7eb;">${module3TargetScoreBar(slice)}</td>\n                <td style="padding:8px;border-bottom:1px solid #e5e7eb;min-width:300px;font-size:12px;color:#475569;">${moduleReasons(slice)}</td>\n            </tr>\n        `;\n    }).join("");\n\n    const module3RangeCard = probable ? `\n        <div style="border:1px solid #bbf7d0;background:#f0fdf4;border-radius:10px;padding:12px;">\n            <div style="font-weight:800;color:#166534;">Module 3 category range</div>\n            <div style="font-size:21px;font-weight:900;color:#15803d;margin-top:3px;">Slices ${probable.startSliceNumber}-${probable.endSliceNumber}</div>\n            <div style="font-size:12px;color:#166534;margin-top:4px;">\n                These slices belong to the uniformity module. Their M3 category scores can correctly be similar.\n            </div>\n        </div>\n    ` : `\n        <div style="border:1px solid #fecaca;background:#fef2f2;border-radius:10px;padding:12px;">\n            <div style="font-weight:800;color:#991b1b;">No confident Module 3 range</div>\n        </div>\n    `;\n\n    let bestSliceCard = `\n        <div style="border:1px solid #fecaca;background:#fef2f2;border-radius:10px;padding:12px;">\n            <div style="font-weight:800;color:#991b1b;">No verified exact BB slice</div>\n            <div style="font-size:12px;color:#7f1d1d;margin-top:4px;">\n                A Module 3 range may exist, but no two-dot pair dominated the noise strongly enough.\n            </div>\n        </div>\n    `;\n\n    if (best) {\n        const statusColor = best.verifiedBestSlice ? "#0e7490" : "#92400e";\n        const background = best.verifiedBestSlice ? "#ecfeff" : "#fffbeb";\n        const border = best.verifiedBestSlice ? "#a5f3fc" : "#fde68a";\n        const distance = best.distanceMm !== null && best.distanceMm !== undefined\n            ? `${Number(best.distanceMm).toFixed(2)} mm`\n            : `${Number(best.distancePixels || 0).toFixed(2)} px`;\n        const supportText = (best.adjacentSupportSlices || []).length\n            ? `Adjacent support: slice${best.adjacentSupportSlices.length === 1 ? "" : "s"} ${best.adjacentSupportSlices.join(", ")}.`\n            : "No adjacent slice showed the same weaker pair.";\n\n        bestSliceCard = `\n            <div style="border:1px solid ${border};background:${background};border-radius:10px;padding:12px;">\n                <div style="font-weight:800;color:${statusColor};">Best exact Module 3 test slice</div>\n                <div style="display:flex;align-items:flex-end;gap:10px;flex-wrap:wrap;margin-top:3px;">\n                    <div style="font-size:30px;font-weight:950;color:${statusColor};">Slice ${best.sliceNumber}</div>\n                    <div style="font-size:14px;font-weight:800;color:${statusColor};padding-bottom:4px;">BB target score ${Number(best.targetScore || 0).toFixed(1)}/100</div>\n                </div>\n                <div style="font-size:12px;color:${statusColor};margin-top:5px;line-height:1.5;">\n                    Dot A: (${best.markerA ? best.markerA.x : "—"}, ${best.markerA ? best.markerA.y : "—"}) ·\n                    Dot B: (${best.markerB ? best.markerB.x : "—"}, ${best.markerB ? best.markerB.y : "—"}) ·\n                    Distance: ${distance}<br>\n                    Second-best: slice ${best.secondBestSliceNumber ?? "—"} at ${best.secondBestTargetScore ?? "—"}/100 ·\n                    Gap: ${best.scoreGapToSecond ?? "—"} points<br>\n                    ${supportText}\n                </div>\n            </div>\n        `;\n    }\n\n    results.innerHTML = `\n        <div style="display:flex;gap:10px;flex-wrap:wrap;">${countCards}</div>\n\n        <div style="display:grid;grid-template-columns:minmax(0,1.5fr) minmax(260px,.75fr) minmax(300px,1fr);gap:12px;margin-top:14px;">\n            <div style="border:1px solid #e2e8f0;border-radius:10px;padding:12px;">\n                <div style="font-weight:800;margin-bottom:8px;">Module Classification Map</div>\n                <div style="display:flex;width:100%;overflow:hidden;border-radius:8px;border:1px solid #cbd5e1;">${map || "No groups"}</div>\n                <div style="font-size:11px;color:#64748b;margin-top:8px;">M1-M4 scores classify the module range; they do not choose the exact BB slice.</div>\n            </div>\n            ${module3RangeCard}\n            ${bestSliceCard}\n        </div>\n\n        <details style="margin-top:14px;border:1px solid #e2e8f0;border-radius:10px;padding:10px;">\n            <summary style="font-weight:800;cursor:pointer;">Grouped slice ranges</summary>\n            <div style="overflow:auto;margin-top:10px;">\n                <table style="width:100%;border-collapse:collapse;font-size:13px;">\n                    <thead><tr style="background:#f8fafc;"><th style="padding:8px;text-align:left;">Slices</th><th style="padding:8px;text-align:left;">Prediction</th><th>Count</th><th>M1</th><th>M2</th><th>M3</th><th>M4</th></tr></thead>\n                    <tbody>${groupRows}</tbody>\n                </table>\n            </div>\n        </details>\n\n        <details open style="margin-top:14px;border:1px solid #e2e8f0;border-radius:10px;padding:10px;">\n            <summary style="font-weight:800;cursor:pointer;">Per-slice classification and exact M3 target ranking</summary>\n            <div style="max-height:520px;overflow:auto;margin-top:10px;border:1px solid #e5e7eb;border-radius:8px;">\n                <table style="width:100%;border-collapse:collapse;font-size:13px;">\n                    <thead style="position:sticky;top:0;background:#f8fafc;z-index:2;">\n                        <tr>\n                            <th style="padding:8px;text-align:left;">Slice</th>\n                            <th style="padding:8px;text-align:left;">Category</th>\n                            <th>M1</th><th>M2</th><th>M3</th><th>M4</th>\n                            <th style="padding:8px;text-align:left;">M3 target</th>\n                            <th style="padding:8px;text-align:left;">Main evidence</th>\n                        </tr>\n                    </thead>\n                    <tbody>${sliceRows}</tbody>\n                </table>\n            </div>\n        </details>\n\n        <div style="margin-top:12px;padding:10px 12px;background:#f8fafc;border-radius:9px;font-size:12px;color:#475569;line-height:1.5;">\n            <strong>Two different scores:</strong> M1-M4 scores answer which module the slice belongs to. The separate M3 target score answers which one exact uniformity slice has the strongest two white BB dots.<br>\n            ${data.scoreNote || ""}<br>\n            Processed ${data.sliceCount || 0} slices in ${data.processingTimeMs || 0} ms. ${data.nextStepNote || ""}\n        </div>\n    `;\n}\n\nasync function requestAcrModuleClassification() {\n    if (\n        typeof currentDicomStackId === "undefined"\n        || !currentDicomStackId\n    ) {\n        throw new Error("Upload a DICOM file or ZIP stack first.");\n    }\n\n    const formData = new FormData();\n    formData.append("stack_id", currentDicomStackId);\n    formData.append("max_size", "160");\n\n    const response = await fetch(\n        "/dicom-module-classification",\n        {\n            method: "POST",\n            body: formData\n        }\n    );\n\n    const responseText = await response.text();\n    let data;\n\n    try {\n        data = JSON.parse(responseText);\n    } catch (error) {\n        throw new Error(\n            `Server returned non-JSON output (${response.status}). `\n            + "Check the Flask terminal for the traceback."\n        );\n    }\n\n    if (!response.ok || !data.success) {\n        throw new Error(\n            data.error || "Module classification failed."\n        );\n    }\n\n    data._stackId = String(currentDicomStackId);\n    window.latestAcrModuleClassification = data;\n\n    return data;\n}\n\n\nfunction hasCurrentVerifiedClassification() {\n    const data = window.latestAcrModuleClassification;\n\n    return Boolean(\n        data\n        && data._stackId === String(currentDicomStackId)\n        && data.bestModule3Slice\n        && data.bestModule3Slice.verifiedBestSlice\n    );\n}\n\n\nasync function runAcrModuleClassification() {\n    const panel = ensureAcrModuleClassifierUi(true);\n    const status = document.getElementById(\n        "acrModuleClassifierStatus"\n    );\n    const results = document.getElementById(\n        "acrModuleClassifierResults"\n    );\n    const button = document.getElementById(\n        "acrSplitModulesButton"\n    );\n\n    status.textContent =\n        "Splitting the stack into Modules 1-4 and ranking the exact Module 3 BB slice...";\n    results.innerHTML = "";\n\n    const originalText = button\n        ? button.textContent\n        : "Split Modules";\n\n    if (button) {\n        button.disabled = true;\n        button.textContent = "Splitting...";\n    }\n\n    try {\n        const data = await requestAcrModuleClassification();\n\n        const bestText = data.bestModule3Slice\n            ? ` Best exact M3 slice: ${data.bestModule3Slice.sliceNumber}.`\n            : " No exact M3 BB slice was verified.";\n\n        status.textContent =\n            `Finished: ${data.sliceCount} slices processed in `\n            + `${data.processingTimeMs} ms.${bestText}`;\n\n        renderAcrModuleClassification(data);\n\n    } catch (error) {\n        status.textContent =\n            `Module split error: ${error.message}`;\n\n        results.innerHTML = `\n            <div style="\n                padding:12px;\n                border:1px solid #fecaca;\n                background:#fef2f2;\n                color:#991b1b;\n                border-radius:9px;\n            ">\n                ${error.message}\n            </div>\n        `;\n    } finally {\n        if (button) {\n            button.disabled = false;\n            button.textContent = originalText;\n        }\n    }\n}\n\nfunction acrModule3ReadNumber(ids, fallback) {\n    for (const id of ids) {\n        const element = document.getElementById(id);\n        if (!element) continue;\n\n        const value = Number(element.value);\n        if (Number.isFinite(value)) return value;\n    }\n\n    return fallback;\n}\n\n\nfunction acrModule3MoveViewerToSlice(sliceIndex) {\n    const possibleSliders = [\n        "dicomSliceSlider",\n        "sliceSlider",\n        "dicomSliceRange",\n        "dicomSliceIndex",\n        "sliceIndex"\n    ];\n\n    for (const id of possibleSliders) {\n        const slider = document.getElementById(id);\n        if (!slider) continue;\n\n        slider.value = String(sliceIndex);\n        slider.dispatchEvent(new Event("input", { bubbles: true }));\n        slider.dispatchEvent(new Event("change", { bubbles: true }));\n        break;\n    }\n\n    if (typeof currentDicomSliceIndex !== "undefined") {\n        currentDicomSliceIndex = sliceIndex;\n    }\n}\n\n\nfunction acrModule3ResultColor(result) {\n    if (result === "PASS") return "#15803d";\n    if (result === "MINOR DEFICIENCY") return "#c2410c";\n    return "#b91c1c";\n}\n\nfunction renderAutomaticModule3Analysis(data) {\n    const container = getOriginalModule3ResultsContainer(true);\n    if (!container) return;\n\n    const resultColor = acrModule3ResultColor(data.finalResult);\n    const support = (data.adjacentSupportSlices || []).length\n        ? data.adjacentSupportSlices.join(", ")\n        : "None";\n\n    const roiRows = (data.rois || []).map((roi) => {\n        const roiColor = acrModule3ResultColor(\n            roi.result === "REFERENCE" ? "PASS" : roi.result\n        );\n\n        return `\n            <tr>\n                <td style="padding:8px;border-bottom:1px solid #e5e7eb;font-weight:700;">${roi.name}</td>\n                <td style="padding:8px;border-bottom:1px solid #e5e7eb;text-align:right;">${Number(roi.mean).toFixed(2)}</td>\n                <td style="padding:8px;border-bottom:1px solid #e5e7eb;text-align:right;">${Number(roi.std).toFixed(2)}</td>\n                <td style="padding:8px;border-bottom:1px solid #e5e7eb;text-align:right;">${Number(roi.diffFromCenter).toFixed(2)}</td>\n                <td style="padding:8px;border-bottom:1px solid #e5e7eb;text-align:right;">${Number(roi.actualAreaMm2).toFixed(2)}</td>\n                <td style="padding:8px;border-bottom:1px solid #e5e7eb;font-weight:800;color:${roiColor};">${roi.result}</td>\n            </tr>\n        `;\n    }).join("");\n\n    container.innerHTML = `\n        <section style="border:2px solid ${resultColor};border-radius:14px;padding:14px;background:#fff;">\n            <div style="display:flex;justify-content:space-between;gap:12px;align-items:flex-start;flex-wrap:wrap;">\n                <div>\n                    <div style="font-size:18px;font-weight:900;">Automatic Module 3 Full Analysis</div>\n                    <div style="font-size:13px;color:#64748b;margin-top:3px;">\n                        Classified the stack, selected the exact verified BB slice, measured distance, and calculated five 400 mm² ROIs.\n                    </div>\n                </div>\n                <div style="font-size:24px;font-weight:950;color:${resultColor};">${data.finalResult}</div>\n            </div>\n\n            <div style="display:grid;grid-template-columns:minmax(300px,1.1fr) minmax(300px,1fr);gap:14px;margin-top:14px;">\n                <div>\n                    <img src="${data.overlayImage}" alt="Automatic Module 3 overlay"\n                        style="display:block;width:100%;max-width:680px;border:1px solid #cbd5e1;border-radius:10px;background:#000;">\n                </div>\n\n                <div style="display:grid;gap:10px;align-content:start;">\n                    <div style="border:1px solid #bae6fd;background:#f0f9ff;border-radius:10px;padding:11px;">\n                        <div style="font-size:12px;color:#0369a1;">Selected exact test slice</div>\n                        <div style="font-size:25px;font-weight:950;color:#0e7490;">Slice ${data.selectedSliceNumber} of ${data.sliceCount}</div>\n                        <div style="font-size:12px;color:#0e7490;margin-top:4px;">\n                            Module 3 range: ${data.module3Range.startSliceNumber}-${data.module3Range.endSliceNumber}<br>\n                            BB target score: ${Number(data.bbTargetScore).toFixed(1)}/100 ·\n                            Gap to second: ${Number(data.bbScoreGapToSecond).toFixed(1)}<br>\n                            Adjacent support slices: ${support}\n                        </div>\n                    </div>\n\n                    <div style="border:1px solid #cffafe;background:#ecfeff;border-radius:10px;padding:11px;">\n                        <div style="font-size:12px;color:#0e7490;">Verified BB distance</div>\n                        <div style="font-size:25px;font-weight:950;color:#0891b2;">${Number(data.bbDistance.mm).toFixed(2)} mm</div>\n                        <div style="font-size:12px;color:#0e7490;">\n                            ${Number(data.bbDistance.pixels).toFixed(2)} pixels ·\n                            A (${Number(data.markerA.x).toFixed(1)}, ${Number(data.markerA.y).toFixed(1)}) ·\n                            B (${Number(data.markerB.x).toFixed(1)}, ${Number(data.markerB.y).toFixed(1)})\n                        </div>\n                    </div>\n\n                    <div style="border:1px solid #e2e8f0;border-radius:10px;padding:11px;">\n                        <div style="font-size:12px;color:#64748b;">ROI geometry</div>\n                        <div style="font-size:18px;font-weight:850;">400 mm² each</div>\n                        <div style="font-size:12px;color:#475569;margin-top:3px;">\n                            Radius ${Number(data.roiSize.radiusMm).toFixed(2)} mm ·\n                            actual mean area ${Number(data.roiSize.actualAreaMeanMm2).toFixed(2)} mm²\n                        </div>\n                    </div>\n                </div>\n            </div>\n\n            <div style="overflow:auto;margin-top:14px;border:1px solid #e5e7eb;border-radius:10px;">\n                <table style="width:100%;border-collapse:collapse;font-size:13px;">\n                    <thead style="background:#f8fafc;">\n                        <tr>\n                            <th style="padding:8px;text-align:left;">ROI</th>\n                            <th style="padding:8px;text-align:right;">Mean HU</th>\n                            <th style="padding:8px;text-align:right;">SD HU</th>\n                            <th style="padding:8px;text-align:right;">Difference from center</th>\n                            <th style="padding:8px;text-align:right;">Area mm²</th>\n                            <th style="padding:8px;text-align:left;">Result</th>\n                        </tr>\n                    </thead>\n                    <tbody>${roiRows}</tbody>\n                </table>\n            </div>\n\n            <div style="margin-top:10px;font-size:12px;color:#475569;line-height:1.5;">\n                Maximum absolute peripheral difference: ${Number(data.maxAbsDiffFromCenter).toFixed(2)} HU.<br>\n                ${data.criteriaNote}\n            </div>\n        </section>\n    `;\n\n    acrModule3MoveViewerToSlice(Number(data.selectedSliceIndex));\n\n    const bottomHost = getDicomBottomHost(true);\n    bottomHost.scrollIntoView({\n        behavior: "smooth",\n        block: "start"\n    });\n}\n\nasync function runAutomaticModule3Analysis(sourceButton = null) {\n    if (\n        typeof currentDicomStackId === "undefined"\n        || !currentDicomStackId\n    ) {\n        showOriginalModule3Status(\n            "Upload a DICOM file or ZIP stack first.",\n            true\n        );\n        return;\n    }\n\n    const button =\n        sourceButton\n        || findOriginalWholeStackButton();\n\n    const originalText = button\n        ? button.textContent\n        : "";\n\n    if (button) {\n        button.disabled = true;\n        button.textContent = "Finding Module 3...";\n    }\n\n    showOriginalModule3Status(\n        "Sorting the four modules, selecting the exact two-BB slice, "\n        + "and running the five-ROI Module 3 analysis..."\n    );\n\n    try {\n        if (!hasCurrentVerifiedClassification()) {\n            await requestAcrModuleClassification();\n        }\n\n        const windowWidth = acrModule3ReadNumber(\n            [\n                "dicomWindowWidth",\n                "windowWidth",\n                "wwSlider",\n                "windowWidthSlider"\n            ],\n            400\n        );\n\n        const windowLevel = acrModule3ReadNumber(\n            [\n                "dicomWindowLevel",\n                "windowLevel",\n                "wlSlider",\n                "windowLevelSlider"\n            ],\n            40\n        );\n\n        const formData = new FormData();\n        formData.append("stack_id", currentDicomStackId);\n        formData.append(\n            "window_width",\n            String(windowWidth)\n        );\n        formData.append(\n            "window_level",\n            String(windowLevel)\n        );\n\n        const response = await fetch(\n            "/dicom-module3-full-analysis",\n            {\n                method: "POST",\n                body: formData\n            }\n        );\n\n        const responseText = await response.text();\n        let data;\n\n        try {\n            data = JSON.parse(responseText);\n        } catch (error) {\n            throw new Error(\n                `Server returned non-JSON output (${response.status}). `\n                + "Check the Flask terminal for the traceback."\n            );\n        }\n\n        if (!response.ok || !data.success) {\n            throw new Error(\n                data.error\n                || "Automatic Module 3 analysis failed."\n            );\n        }\n\n        renderAutomaticModule3Analysis(data);\n\n    } catch (error) {\n        showOriginalModule3Status(\n            `Automatic Module 3 error: ${error.message}`,\n            true\n        );\n    } finally {\n        if (button) {\n            button.disabled = false;\n            button.textContent = originalText;\n        }\n    }\n}\n\n\nfunction startAcrModuleUiCleanup() {\n    setupAcrModuleControls();\n\n    // Some parts of the page may be rebuilt after a DICOM upload. Reapply the\n    // bindings without adding duplicate buttons.\n    const observer = new MutationObserver(() => {\n        bindOriginalWholeStackButton();\n        ensureSplitModulesButton();\n    });\n\n    observer.observe(document.body, {\n        childList: true,\n        subtree: true\n    });\n}\n\n\ndocument.addEventListener(\n    "DOMContentLoaded",\n    startAcrModuleUiCleanup\n);\n'


